#include <stdio.h>
#include <stdlib.h>

int minWindow(int* arr, int n, int k) {
    int* freq = (int*)calloc(k + 1, sizeof(int));
    int distinct = 0;
    int minLen = n + 1;
    int left = 0;
    for (int right = 0; right < n; right++) {
        if (freq[arr[right]] == 0) distinct++;
        freq[arr[right]]++;
        while (distinct == k) {
            minLen = (minLen < right - left + 1) ? minLen : right - left + 1;
            freq[arr[left]]--;
            if (freq[arr[left]] == 0) distinct--;
            left++;
        }
    }
    free(freq);
    return minLen == n + 1 ? -1 : minLen;
}

int main() {
    int n, k, q;
    scanf("%d %d %d", &n, &k, &q);
    int* arr = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) scanf("%d", &arr[i]);
    for (int i = 0; i < q; i++) {
        int xi, yi;
        scanf("%d %d", &xi, &yi);
        arr[xi - 1] = yi;
        printf("%d\n", minWindow(arr, n, k));
    }
    free(arr);
    return 0;
}

