using namespace std;

int minWindow(vector<int>& arr, int k) {
    vector<int> freq(k + 1, 0);
    int distinct = 0;
    int minLen = arr.size() + 1;
    int left = 0;
    for (int right = 0; right < arr.size(); right++) {
        if (freq[arr[right]] == 0) distinct++;
        freq[arr[right]]++;
        while (distinct == k) {
            minLen = min(minLen, right - left + 1);
            freq[arr[left]]--;
            if (freq[arr[left]] == 0) distinct--;
            left++;
        }
    }
    return minLen == arr.size() + 1 ? -1 : minLen;
}

int main() {
    int n, k, q;
    cin >> n >> k >> q;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    for (int i = 0; i < q; i++) {
        int xi, yi;
