import java.util.Scanner;
public class Main {
    public static int minWindow(int[] arr, int k) {
        int[] freq = new int[k + 1];
        int distinct = 0;
        int minLen = arr.length + 1;
        int left = 0;
        for (int right = 0; right < arr.length; right++) {
            if (freq[arr[right]] == 0) distinct++;
            freq[arr[right]]++;
            while (distinct == k) {
                minLen = Math.min(minLen, right - left + 1);
                freq[arr[left]]--;
                if (freq[arr[left]] == 0) distinct--;
                left++;
            }
        }
        return minLen == arr.length + 1 ? -1 : minLen;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int k = sc.nextInt();
        int q = sc.nextInt();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) arr[i] = sc.nextInt();
        for (int i = 0; i < q; i++) {
            int xi = sc.nextInt();
            int yi = sc.nextInt();
            arr[xi - 1] = yi;
            System.out.println(minWindow(arr, k));
        }
    }
}

